import type { Metadata } from "next";
import MedicationAdministration from "./MedicationAdministration";

export const metadata: Metadata = {
  title: "与薬 / 配薬・3点認証 | ぐんじょう eMAR",
  description:
    "ベッドサイド与薬（配薬）・3点認証の電子カルテ画面。患者バナー（患者ID / 氏名 / 年齢・性別 / 病棟・病室・ベッド / 担当看護師）とアレルギー・禁忌の警告を常時表示。与薬指示一覧（薬剤名 / 規格 / 用量 / 投与経路（経口・点滴静注・皮下注・筋注）/ 投与時刻（定時 / 頓用）/ 状態 / ハイアラート / 投与時刻ウィンドウ ±30分）に対し、① 患者リストバンド → ② 薬剤 の3点認証（患者不一致・指示に無い薬剤・中止済・時刻外をブロックして読み上げ）、アレルギー／相互作用の必須確認、ハイアラート薬のダブルチェック（2人確認）、与薬前バイタル（インスリン→血糖・降圧薬→血圧）を満たして与薬実施を記録、または保留／拒薬／中止を理由付きで記録します。",
};

export default function MedicationPage() {
  return <MedicationAdministration />;
}

// 与薬 / 配薬・3点認証 — clinical domain model + seed data.
// All barcodes here are demo codes; a real eMAR would resolve against HL7/HOT codes.

export type Route = "経口" | "点滴静注" | "皮下注" | "筋注" | "外用";
export type OrderStatus = "未実施" | "実施済" | "保留" | "中止";

export interface Patient {
  id: string; // 患者ID
  wristbandCode: string; // リストバンドのバーコード
  name: string;
  kana: string;
  age: number;
  sex: "男" | "女";
  ward: string; // 病棟
  room: string; // 病室
  bed: string; // ベッド
  nurse: string; // 担当看護師
  /** アレルギー — the single loudest safety element. */
  allergies: string[];
  /** 禁忌・注意フラグ. */
  cautions: string[];
}

export interface MedOrder {
  id: string; // 指示ID
  drugCode: string; // 薬剤バーコード (GS1 / HOT 相当)
  name: string; // 薬剤名
  spec: string; // 規格
  dose: string; // 用量
  route: Route; // 投与経路
  schedule: string; // 投与時刻 (定時 "08:00" / "頓用")
  scheduledAt: string | null; // "HH:MM" or null for 頓用
  status: OrderStatus;
  /** ハイアラート薬 (インスリン・抗凝固薬・麻薬 等) → ダブルチェック必須. */
  highAlert: boolean;
  highAlertReason?: string;
  /** スキャンした薬剤がこのアレルゲンに該当するとアレルギーブロック. */
  allergyConflict?: string;
  /** 与薬前に必要なバイタル (例: インスリン→血糖, 降圧薬→血圧). */
  requiredVital?: { label: string; unit: string; min?: number; max?: number; note: string };
  /** 既に実施済みの場合の記録. */
  administeredAt?: string;
  administeredBy?: string;
}

export const PATIENT: Patient = {
  id: "P-0042178",
  wristbandCode: "PT0042178",
  name: "佐藤 花子",
  kana: "サトウ ハナコ",
  age: 78,
  sex: "女",
  ward: "東4病棟",
  room: "412",
  bed: "A",
  nurse: "山田 看護師",
  allergies: ["ペニシリン", "造影剤"],
  cautions: ["転倒リスク", "腎機能低下 (eGFR 38)"],
