// 現在時刻は 08:10 想定（定時 08:00 の与薬ラウンド）。
export const NOW_LABEL = "08:10";
export const NOW_MINUTES = 8 * 60 + 10;
export const WINDOW_MINUTES = 30; // 与薬時刻 ±30分

export const ORDERS: MedOrder[] = [
  {
    id: "ORD-1001",
