    schedule: "08:00",
    scheduledAt: "08:00",
    status: "未実施",
    highAlert: false,
    allergyConflict: "ペニシリン", // ← 患者はペニシリンアレルギー → 与薬ブロック
  },
  {
    id: "ORD-1005",
