    requiredVital: {
      label: "収縮期血圧",
      unit: "mmHg",
      min: 90,
      max: 200,
      note: "投与前収縮期血圧が90mmHg未満の場合は降圧薬を保留。",
    },
  },
  {
    id: "ORD-1006",
    drugCode: "DRUG-CEFAZOLIN-1G",
    name: "セファゾリンNa点滴静注",
