    administeredBy: "鈴木 看護師",
  },
];

export const HOLD_REASONS = [
  "患者拒否（拒薬）",
  "嘔気・嘔吐",
  "絶食・検査前",
  "バイタル基準外（医師報告）",
  "患者不在",
  "その他（コメント参照）",
] as const;

/** 与薬時刻に対するウィンドウ判定。 */
export function windowState(
  order: MedOrder
): "within" | "early" | "overdue" | "prn" {
  if (order.scheduledAt === null) return "prn"; // 頓用
  const [h, m] = order.scheduledAt.split(":").map(Number);
  const sched = h * 60 + m;
  const diff = NOW_MINUTES - sched; // +なら遅れ
  if (diff > WINDOW_MINUTES) return "overdue";
  if (diff < -WINDOW_MINUTES) return "early";
  return "within";
}

export function statusTone(
  status: OrderStatus
): "success" | "warning" | "destructive" | "secondary" {
  switch (status) {
    case "実施済":
      return "success";
    case "保留":
      return "warning";
    case "中止":
      return "destructive";
    default:
      return "secondary";
  }
}

"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconBan,
  IconCircleCheck,
  IconClockHour4,
  IconHeartbeat,
  IconScan,
  IconShieldCheckered,
  IconUserShield,
  IconVaccine,
  IconPill,
  IconDroplet,
  IconLock,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Checkbox,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Input,
  NumberInput,
  ScanGate,
  type ScanGateHandle,
  Select,
  Separator,
  Statistic,
  Textarea,
} from "@gunjo/ui";

import {
  HOLD_REASONS,
  NOW_LABEL,
  ORDERS,
  PATIENT,
  statusTone,
  windowState,
  type MedOrder,
  type OrderStatus,
  type Route,
} from "./data";

// ── route → icon (icon+text, never colour-alone) ─────────────────────────────
type IconType = React.ComponentType<React.SVGProps<SVGSVGElement>>;
const ROUTE_ICON: Record<Route, IconType> = {
  経口: IconPill,
  点滴静注: IconDroplet,
  皮下注: IconVaccine,
  筋注: IconVaccine,
  外用: IconPill,
};

const WINDOW_LABEL: Record<ReturnType<typeof windowState>, string> = {
  within: "時刻内",
  early: "時刻前",
  overdue: "時刻外（超過）",
  prn: "頓用",
};

type VerifyState =
  | { kind: "prescan" } // 認証前
  | { kind: "patientok" } // 患者照合OK、薬剤待ち
  | { kind: "verified"; order: MedOrder } // 3点認証OK
  | { kind: "blocked"; reason: string; detail: string }; // 安全ブロック（読み上げ）

interface Recorded {
  status: Exclude<OrderStatus, "未実施">;
  at: string;
  by: string;
  note?: string;
}

interface GatesState {
  needsAllergyAck: boolean;
  allergyOk: boolean;
  needsDoubleCheck: boolean;
  doubleCheckOk: boolean;
  needsVital: boolean;
  vitalOk: boolean;
  vitalRecorded: boolean;
  outOfWindow: boolean;
  win: ReturnType<typeof windowState>;
}

function nowClock(): string {
  const d = new Date();
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
}

export default function MedicationAdministration() {
  const scanRef = React.useRef<ScanGateHandle>(null);

  // 各指示の記録状態（実施 / 保留 / 中止）。
  const [records, setRecords] = React.useState<Record<string, Recorded>>(() => {
    const seed: Record<string, Recorded> = {};
    for (const o of ORDERS) {
      if (o.status === "実施済" && o.administeredAt && o.administeredBy) {
        seed[o.id] = { status: "実施済", at: o.administeredAt, by: o.administeredBy };
      } else if (o.status === "中止") {
        seed[o.id] = { status: "中止", at: "—", by: "医師指示" };
      }
    }
    return seed;
  });

  // 3点認証の状態機械。
  const [verify, setVerify] = React.useState<VerifyState>({ kind: "prescan" });
  // ブロックを読み上げ直すための remount キー（Alert role="alert" は挿入時のみ発話するため）。
  const [blockSeq, setBlockSeq] = React.useState(0);

  // 各種人間による確認（acknowledgement）。
  const [allergyAck, setAllergyAck] = React.useState(false);
  const [doubleCheck, setDoubleCheck] = React.useState<{ nurseId: string } | null>(null);
  const [vital, setVital] = React.useState<number | undefined>(undefined);

  // モーダル。
  const [doubleCheckOpen, setDoubleCheckOpen] = React.useState(false);
  const [holdOpen, setHoldOpen] = React.useState(false);

  const effectiveStatus = React.useCallback(
    (o: MedOrder): OrderStatus => records[o.id]?.status ?? "未実施",
    [records]
  );

  const dueOrders = ORDERS.filter((o) => effectiveStatus(o) === "未実施");
  const summary = {
    実施済: ORDERS.filter((o) => effectiveStatus(o) === "実施済").length,
    保留: ORDERS.filter((o) => effectiveStatus(o) === "保留").length,
    未実施: dueOrders.length,
  };

  const activeOrder = verify.kind === "verified" ? verify.order : null;

  // 与薬実施の前提が全て満たされているか。
  const gates = React.useMemo<GatesState | null>(() => {
    if (!activeOrder) return null;
    const win = windowState(activeOrder);
    const needsAllergyAck = Boolean(activeOrder.allergyConflict);
    const needsDoubleCheck = activeOrder.highAlert;
    const needsVital = Boolean(activeOrder.requiredVital);
    const vitalRange = activeOrder.requiredVital;
    const vitalOk =
      !needsVital ||
      (vital !== undefined &&
        (vitalRange?.min === undefined || vital >= vitalRange.min) &&
        (vitalRange?.max === undefined || vital <= vitalRange.max));
    const outOfWindow = win === "overdue" || win === "early";
    return {
      needsAllergyAck,
      allergyOk: !needsAllergyAck || allergyAck,
      needsDoubleCheck,
      doubleCheckOk: !needsDoubleCheck || doubleCheck !== null,
      needsVital,
      vitalOk,
      vitalRecorded: vital !== undefined,
      outOfWindow,
      win,
    };
  }, [activeOrder, allergyAck, doubleCheck, vital]);

  const canAdminister = Boolean(
    activeOrder &&
      gates &&
      gates.allergyOk &&
      gates.doubleCheckOk &&
      gates.vitalOk &&
      !gates.outOfWindow
  );

  function resetVerification() {
    setVerify({ kind: "prescan" });
    setAllergyAck(false);
    setDoubleCheck(null);
    setVital(undefined);
    scanRef.current?.reset();
  }

  function block(reason: string, detail: string) {
    setVerify({ kind: "blocked", reason, detail });
    setBlockSeq((s) => s + 1);
  }

  // ── ScanGate stages: ① リストバンド → ② 薬剤 → 3点照合 ──────────────────────
  const stages = React.useMemo(
    () => [
      {
        id: "patient",
        title: "① 患者",
        label: "患者リストバンドをスキャン",
        description: "ベッドサイドで患者本人のリストバンドのバーコードを読み取ってください。",
        placeholder: "リストバンド バーコード",
        onScan: (code: string) => {
          if (code.trim() !== PATIENT.wristbandCode) {
            block(
              "患者不一致",
              `スキャンされたリストバンド（${code}）は ${PATIENT.name}（${PATIENT.id}）と一致しません。別の患者の可能性があります。与薬を中止してください。`
            );
            return { ok: false, message: "患者不一致：リストバンドが一致しません", advance: "stay" as const };
          }
          setVerify({ kind: "patientok" });
          return {
            ok: true,
            message: `患者照合OK：${PATIENT.name}`,
            advance: "next" as const,
            value: PATIENT.id,
          };
        },
      },
      {
        id: "drug",
        title: "② 薬剤",
        label: "薬剤バーコードをスキャン",
        description: "これから与薬する薬剤の包装／アンプルのバーコードを読み取ってください。",
        placeholder: "薬剤 バーコード",
        onScan: (code: string) => {
          const trimmed = code.trim();
          const order = ORDERS.find((o) => o.drugCode === trimmed);

          // 指示に無い薬剤。
          if (!order) {
            block(
              "指示に無い薬剤",
              `スキャンされた薬剤（${trimmed}）は ${PATIENT.name} の現在の指示にありません。指示を確認してください。`
            );
            return { ok: false, message: "指示に無い薬剤：照合できません", advance: "stay" as const };
          }
          // 中止済の指示。
          if (effectiveStatus(order) === "中止") {
            block(
              "中止済の指示",
              `${order.name} は中止された指示です（医師指示による中止）。与薬しないでください。`
            );
            return { ok: false, message: `中止済：${order.name} は与薬できません`, advance: "stay" as const };
          }
          // 既に実施済。
          if (effectiveStatus(order) === "実施済") {
            block(
              "実施済の指示",
              `${order.name} は既に実施済みです。重複与薬を避けてください。`
            );
            return { ok: false, message: `実施済：${order.name} は記録済みです`, advance: "stay" as const };
          }
          // 時刻外（超過／前）— 警告ブロック（オーバーライド可だが既定はブロック）。
          const win = windowState(order);
          if (win === "overdue" || win === "early") {
            block(
              "投与時刻外",
              `${order.name} の与薬時刻は ${order.schedule} です（現在 ${NOW_LABEL}）。時刻外のため、理由を付けて与薬するか保留してください。`
            );
            return {
              ok: false,
              message: `時刻外：${order.name}（指示 ${order.schedule}）`,
              advance: "stay" as const,
            };
          }
          // ── 3点認証成立 ──
          // last stage: `stay` ではなく `next` だと ScanGate が先頭へラップして
          // しまうため、認証成立後は明示的に `stay` で薬剤ステージに留め、
          // 認証済みの状態（実施パネル）を保持する。
          setVerify({ kind: "verified", order });
          setAllergyAck(false);
          setDoubleCheck(null);
          setVital(undefined);
          return {
            ok: true,
            message: `3点認証OK：${PATIENT.name} / ${order.name}`,
            advance: "stay" as const,
            value: order.id,
          };
        },
      },
    ],
    [effectiveStatus]
  );

  function administer() {
    if (!activeOrder || !canAdminister) return;
    const note = activeOrder.requiredVital && vital !== undefined
      ? `${activeOrder.requiredVital.label} ${vital}${activeOrder.requiredVital.unit}` +
        (doubleCheck ? ` / ダブルチェック: ${doubleCheck.nurseId}` : "")
      : doubleCheck
      ? `ダブルチェック: ${doubleCheck.nurseId}`
      : undefined;
    setRecords((r) => ({
      ...r,
      [activeOrder.id]: { status: "実施済", at: nowClock(), by: PATIENT.nurse, note },
    }));
    resetVerification();
  }

  function recordHold(status: "保留" | "中止", reason: string, comment: string) {
    if (!activeOrder) return;
    setRecords((r) => ({
      ...r,
      [activeOrder.id]: {
        status,
        at: nowClock(),
        by: PATIENT.nurse,
        note: comment ? `${reason}：${comment}` : reason,
      },
    }));
    setHoldOpen(false);
    resetVerification();
  }

  return (
    <main className="mx-auto flex w-full max-w-5xl flex-col gap-4 px-4 py-4 sm:px-6 sm:py-6">
      <header className="flex flex-col gap-1">
        <p className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
          与薬 / 配薬・3点認証 — bedside eMAR
        </p>
        <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
          <IconShieldCheckered className="h-7 w-7 text-primary" aria-hidden="true" />
          ベッドサイド与薬・3点認証
        </h1>
        <p className="text-sm text-muted-foreground">
          正しい患者・薬剤・指示を照合し、アレルギー／ハイアラートを確認のうえ安全に与薬します（現在 {NOW_LABEL}）。
        </p>
      </header>

      {/* ── 患者バナー（安全最優先・常時表示） ───────────────────────────────── */}
      <PatientBanner />

      {/* ── サマリ ───────────────────────────────────────────────────────── */}
      <section aria-label="与薬サマリ" className="grid grid-cols-3 gap-3">
        <Statistic label="未実施" value={summary.未実施} tone="neutral" hint="この時間帯の残り" />
        <Statistic label="実施済" value={summary.実施済} tone="positive" change="記録済" trend="up" />
        <Statistic label="保留 / 中止" value={summary.保留} tone="negative" hint="要フォロー" />
      </section>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-[1fr_minmax(320px,420px)]">
        {/* ── 与薬指示一覧 ─────────────────────────────────────────────── */}
        <Card>
          <CardHeader className="pb-3">
            <CardTitle as="h2" className="flex items-center gap-2 text-lg">
              <IconClockHour4 className="h-5 w-5" aria-hidden="true" />
              与薬指示一覧
            </CardTitle>
          </CardHeader>
          <CardContent className="flex flex-col gap-2.5">
            {ORDERS.map((o) => (
              <OrderRow
                key={o.id}
                order={o}
                status={effectiveStatus(o)}
                active={activeOrder?.id === o.id}
                record={records[o.id]}
              />
            ))}
          </CardContent>
        </Card>

        {/* ── 3点認証 + 実施記録 ───────────────────────────────────────── */}
        <div className="flex flex-col gap-4">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconScan className="h-5 w-5" aria-hidden="true" />
                3点認証
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-3">
              <ScanGate ref={scanRef} stages={stages} lockMs={250} />

              {/* 安全ブロックの読み上げ（assertive を別 Alert で補強） */}
              {verify.kind === "blocked" ? (
                <div key={blockSeq} aria-live="assertive">
                  <Alert variant="destructive">
                    <IconBan className="h-4 w-4" aria-hidden="true" />
                    <AlertTitle as="h3">スキャン照合エラー：{verify.reason}</AlertTitle>
                    <AlertDescription>{verify.detail}</AlertDescription>
                  </Alert>
                  <div className="mt-2 flex gap-2">
                    <Button variant="outline" size="sm" onClick={resetVerification}>
                      最初からやり直す
                    </Button>
                  </div>
                </div>
              ) : null}

              {verify.kind === "prescan" ? (
                <p className="rounded-lg border border-dashed border-border bg-muted/30 px-3 py-2 text-xs text-muted-foreground">
                  ① 患者リストバンド → ② 薬剤 の順にスキャンしてください。スキャンガンはコードを入力後 Enter を送出します。
                </p>
              ) : null}
            </CardContent>
          </Card>

          {/* ── 実施パネル（3点認証成立後のみ） ─────────────────────────── */}
          {activeOrder && gates ? (
            <Card aria-label="与薬実施パネル">
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconCircleCheck className="h-5 w-5 text-success" aria-hidden="true" />
                  与薬実施
                </CardTitle>
              </CardHeader>
              <CardContent className="flex flex-col gap-4">
                <Alert variant="success">
                  <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle as="h3">3点認証OK</AlertTitle>
                  <AlertDescription>
                    {PATIENT.name}（{PATIENT.id}） / {activeOrder.name} {activeOrder.dose}・{activeOrder.route}
                  </AlertDescription>
                </Alert>

                {/* アレルギーブロック（該当時・要明示確認） */}
                {gates.needsAllergyAck ? (
                  <div aria-live="assertive">
                    <Alert variant="destructive">
                      <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                      <AlertTitle as="h3">アレルギー警告：{activeOrder.allergyConflict}</AlertTitle>
                      <AlertDescription className="flex flex-col gap-2">
                        <span>
                          この患者は <strong>{activeOrder.allergyConflict}アレルギー</strong> です。
                          {activeOrder.name} は禁忌の可能性があります。投与前に医師へ確認してください。
                        </span>
                        <Checkbox
                          checked={allergyAck}
                          onCheckedChange={setAllergyAck}
                          label="医師に確認し、投与の指示を得たことを確認しました"
                        />
                      </AlertDescription>
                    </Alert>
                  </div>
                ) : null}

                {/* ハイアラート → ダブルチェック */}
                {gates.needsDoubleCheck ? (
                  <Alert variant={doubleCheck ? "success" : "warning"}>
                    {doubleCheck ? (
                      <IconShieldCheckered className="h-4 w-4" aria-hidden="true" />
                    ) : (
                      <IconUserShield className="h-4 w-4" aria-hidden="true" />
                    )}
                    <AlertTitle as="h3">
                      ハイアラート薬：ダブルチェック{doubleCheck ? "完了" : "必須"}
                    </AlertTitle>
                    <AlertDescription className="flex flex-col gap-2">
                      <span>
                        {activeOrder.highAlertReason}のため、2人目の看護師による確認が必要です。
                        {doubleCheck ? `（確認者：${doubleCheck.nurseId}）` : ""}
                      </span>
                      <div>
                        <Button
                          variant={doubleCheck ? "outline" : "warning"}
                          size="sm"
                          onClick={() => setDoubleCheckOpen(true)}
                        >
                          {doubleCheck ? "ダブルチェックを修正" : "ダブルチェックを実施"}
                        </Button>
                      </div>
                    </AlertDescription>
                  </Alert>
                ) : null}

                {/* 与薬前バイタル */}
                {gates.needsVital && activeOrder.requiredVital ? (
                  <div className="flex flex-col gap-2 rounded-lg border border-border p-3">
                    <div className="flex items-center gap-2 text-sm font-medium">
                      <IconHeartbeat className="h-4 w-4 text-info" aria-hidden="true" />
                      与薬前バイタル：{activeOrder.requiredVital.label}
                    </div>
                    <p className="text-xs text-muted-foreground">{activeOrder.requiredVital.note}</p>
                    <div className="flex items-end gap-2">
                      <div className="flex flex-col gap-1.5">
                        <label
                          htmlFor="vital-input"
                          className="text-xs font-medium text-foreground"
                        >
                          {activeOrder.requiredVital.label}（{activeOrder.requiredVital.unit}）
                        </label>
                        <NumberInput
                          id="vital-input"
                          value={vital}
                          onValueChange={setVital}
                          min={0}
                          max={999}
                          step={1}
                          aria-label={`${activeOrder.requiredVital.label}（${activeOrder.requiredVital.unit}）`}
                        />
                      </div>
                      {gates.vitalRecorded ? (
                        gates.vitalOk ? (
                          <Badge variant="success" className="mb-1.5">
                            <IconCircleCheck className="mr-1 h-3 w-3" aria-hidden="true" />
                            基準内
                          </Badge>
                        ) : (
                          <Badge variant="destructive" className="mb-1.5">
                            <IconAlertTriangle className="mr-1 h-3 w-3" aria-hidden="true" />
                            基準外・保留検討
                          </Badge>
                        )
                      ) : null}
                    </div>
                    {gates.vitalRecorded && !gates.vitalOk ? (
                      <p role="alert" className="text-xs font-medium text-destructive">
                        基準範囲（{activeOrder.requiredVital.min}–{activeOrder.requiredVital.max}
                        {activeOrder.requiredVital.unit}）外です。与薬を保留し医師へ報告してください。
                      </p>
                    ) : null}
                  </div>
                ) : null}

                {/* 実施前提チェックリスト */}
                <ChecklistSummary gates={gates} />

                {/* アクション */}
                <div className="flex flex-col gap-2">
                  <Button
                    variant="success"
                    size="lg"
                    className="w-full"
                    disabled={!canAdminister}
                    onClick={administer}
                  >
                    {canAdminister ? (
                      <>
                        <IconCircleCheck className="h-5 w-5" aria-hidden="true" />
                        与薬実施を記録
                      </>
                    ) : (
                      <>
                        <IconLock className="h-5 w-5" aria-hidden="true" />
                        前提を満たすと実施できます
                      </>
                    )}
                  </Button>
                  <div className="grid grid-cols-2 gap-2">
                    <Button variant="warning" onClick={() => setHoldOpen(true)}>
                      保留 / 拒薬
                    </Button>
                    <Button variant="outline" onClick={resetVerification}>
                      認証をやり直す
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ) : null}
        </div>
      </div>

      {/* ── ダブルチェック composer (Dialog) ─────────────────────────────── */}
      <DoubleCheckDialog
        open={doubleCheckOpen}
        order={activeOrder}
        onOpenChange={setDoubleCheckOpen}
        onConfirm={(nurseId) => {
          setDoubleCheck({ nurseId });
          setDoubleCheckOpen(false);
        }}
      />

      {/* ── 保留 / 中止 (Dialog) ─────────────────────────────────────────── */}
      <HoldDialog
        open={holdOpen}
        order={activeOrder}
        onOpenChange={setHoldOpen}
        onSubmit={recordHold}
      />
    </main>
  );
}

