    </div>
  );
}

// ── 実施前提チェックリスト ────────────────────────────────────────────────────
function ChecklistSummary({ gates }: { gates: GatesState }) {
  const items: { ok: boolean; required: boolean; label: string }[] = [
    { ok: true, required: true, label: "3点認証（患者・薬剤・指示）" },
    {
      ok: gates.allergyOk,
      required: gates.needsAllergyAck,
      label: "アレルギー確認",
    },
    {
      ok: gates.doubleCheckOk,
      required: gates.needsDoubleCheck,
      label: "ダブルチェック（2人確認）",
    },
    {
      ok: gates.vitalOk && gates.vitalRecorded,
      required: gates.needsVital,
      label: "与薬前バイタル",
    },
    {
      ok: !gates.outOfWindow,
      required: true,
      label: "投与時刻ウィンドウ（±30分）",
    },
  ].filter((i) => i.required);

  return (
    <ul className="flex flex-col gap-1.5 rounded-lg bg-muted/40 p-3 text-sm" aria-label="実施前提">
      {items.map((i) => (
        <li key={i.label} className="flex items-center gap-2">
          {i.ok ? (
            <IconCircleCheck className="h-4 w-4 shrink-0 text-success" aria-hidden="true" />
          ) : (
            <IconAlertTriangle className="h-4 w-4 shrink-0 text-warning" aria-hidden="true" />
          )}
          <span className={i.ok ? "text-foreground" : "font-medium text-foreground"}>
            {i.label}
          </span>
          <span className="ml-auto text-xs">
            {i.ok ? (
              <span className="text-success">OK</span>
            ) : (
              <span className="text-warning">未完了</span>
            )}
          </span>
        </li>
      ))}
    </ul>
  );
}

// ── ダブルチェック Dialog ─────────────────────────────────────────────────────
function DoubleCheckDialog({
  open,
  order,
  onOpenChange,
  onConfirm,
}: {
  open: boolean;
  order: MedOrder | null;
  onOpenChange: (o: boolean) => void;
  onConfirm: (nurseId: string) => void;
}) {
  const [nurseId, setNurseId] = React.useState("");
  const [checks, setChecks] = React.useState({ drug: false, dose: false, route: false });
  React.useEffect(() => {
    if (open) {
      setNurseId("");
      setChecks({ drug: false, dose: false, route: false });
    }
  }, [open]);

  const sameAsPrimary = nurseId.trim() === PATIENT.nurse;
  const allChecked = checks.drug && checks.dose && checks.route;
  const canConfirm = nurseId.trim().length >= 2 && allChecked && !sameAsPrimary;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>ダブルチェック（2人確認）</DialogTitle>
          <DialogDescription>
            ハイアラート薬の与薬には2人目の看護師による独立確認が必要です。
            {order ? `（対象：${order.name} ${order.dose}・${order.route}）` : ""}
          </DialogDescription>
        </DialogHeader>

        <div className="flex flex-col gap-4">
          <div className="flex flex-col gap-1.5">
            <label htmlFor="dc-nurse" className="text-sm font-medium">
              2人目看護師ID / 氏名
            </label>
            <Input
              id="dc-nurse"
              value={nurseId}
              onChange={(e) => setNurseId(e.target.value)}
              placeholder="例：佐々木 看護師"
              aria-invalid={sameAsPrimary || undefined}
              aria-describedby={sameAsPrimary ? "dc-nurse-err" : undefined}
            />
            {sameAsPrimary ? (
              <p id="dc-nurse-err" role="alert" className="text-xs font-medium text-destructive">
                実施者（{PATIENT.nurse}）と同一人物では確認になりません。別の看護師を指定してください。
              </p>
            ) : null}
          </div>

          <fieldset className="flex flex-col gap-2">
            <legend className="mb-1 text-sm font-medium">確認項目（2人目が独立に確認）</legend>
            <Checkbox
              checked={checks.drug}
              onCheckedChange={(v) => setChecks((c) => ({ ...c, drug: v }))}
              label="薬剤名・規格が指示と一致"
            />
            <Checkbox
              checked={checks.dose}
              onCheckedChange={(v) => setChecks((c) => ({ ...c, dose: v }))}
              label="用量が指示と一致"
            />
            <Checkbox
              checked={checks.route}
              onCheckedChange={(v) => setChecks((c) => ({ ...c, route: v }))}
              label="投与経路・投与時刻が指示と一致"
            />
          </fieldset>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          <Button variant="success" disabled={!canConfirm} onClick={() => onConfirm(nurseId.trim())}>
            <IconShieldCheckered className="h-4 w-4" aria-hidden="true" />
            ダブルチェック確定
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

// ── 保留 / 中止 Dialog ────────────────────────────────────────────────────────
function HoldDialog({
  open,
  order,
  onOpenChange,
  onSubmit,
}: {
  open: boolean;
  order: MedOrder | null;
  onOpenChange: (o: boolean) => void;
  onSubmit: (status: "保留" | "中止", reason: string, comment: string) => void;
}) {
  const [status, setStatus] = React.useState<"保留" | "中止">("保留");
  const [reason, setReason] = React.useState<string>(HOLD_REASONS[0]);
  const [comment, setComment] = React.useState("");
  React.useEffect(() => {
    if (open) {
      setStatus("保留");
      setReason(HOLD_REASONS[0]);
      setComment("");
    }
  }, [open]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>保留 / 中止の記録</DialogTitle>
          <DialogDescription>
            {order ? `${order.name} ${order.dose}・${order.route}` : ""}
            の与薬を実施せず記録します。理由は必須です。
          </DialogDescription>
        </DialogHeader>

        <div className="flex flex-col gap-4">
          <Select
            label="区分"
            value={status}
            onChange={(e) => setStatus(e.target.value as "保留" | "中止")}
          >
            <option value="保留">保留（後で再評価）</option>
            <option value="中止">中止（このラウンドは与薬しない）</option>
          </Select>

          <Select
            label="理由"
            value={reason}
            onChange={(e) => setReason(e.target.value)}
          >
            {HOLD_REASONS.map((r) => (
              <option key={r} value={r}>
                {r}
              </option>
            ))}
          </Select>

          <div className="flex flex-col gap-1.5">
            <label htmlFor="hold-comment" className="text-sm font-medium">
              コメント（任意）
            </label>
            <Textarea
              id="hold-comment"
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              placeholder="状況・医師への報告内容など"
              rows={3}
            />
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          <Button variant="warning" onClick={() => onSubmit(status, reason, comment)}>
            {status}として記録
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}
